mapper.select:
SELECT FORMULAR_NO, ITEM_NO, CONDITION, FORMULAR, CONDITION_SEQ,
       DESCRIPTION, CPNY_ID, MIN_SEQ, MAX_SEQ
  FROM (
    SELECT a.*, ROWNUM AS RN
      FROM (

        ORDER BY CONDITION_SEQ DESC
      ) a
     WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC}
  )
 WHERE RN > #{start, jdbcType=NUMERIC}

SELECT FORMULAR_NO, ITEM_NO, CONDITION, FORMULAR, CONDITION_SEQ, DESCRIPTION, CPNY_ID
  FROM PA_FORMULAR
 WHERE FORMULAR_NO = #{formularNo, jdbcType=NUMERIC}

SELECT FORMULAR_NO, CONDITION_SEQ
  FROM PA_FORMULAR
 WHERE ITEM_NO  = #{itemNo,  jdbcType=VARCHAR}
   AND CPNY_ID  = #{cpnyId,  jdbcType=VARCHAR}
   AND CONDITION_SEQ = (


               SELECT MIN(CONDITION_SEQ) FROM PA_FORMULAR
                WHERE ITEM_NO  = #{itemNo,  jdbcType=VARCHAR}
                  AND CPNY_ID  = #{cpnyId,  jdbcType=VARCHAR}
                  AND CONDITION_SEQ > #{currentSeq, jdbcType=NUMERIC}


               SELECT MAX(CONDITION_SEQ) FROM PA_FORMULAR
                WHERE ITEM_NO  = #{itemNo,  jdbcType=VARCHAR}
                  AND CPNY_ID  = #{cpnyId,  jdbcType=VARCHAR}
                  AND CONDITION_SEQ < #{currentSeq, jdbcType=NUMERIC}


   )
